package com.example.lessondesign.dao; import com.example.lessondesign.bean.ClassExercise; import org.apache.ibatis.annotations.*; import java.util.*; @Mapper public interface ClassExerciseDao { @Insert("INSERT INTO class_exercise (class_id,exercise_id,created_at,end_time) VALUES (#{classId},#{exerciseId},#{createdAt},#{endTime})") @Options(useGeneratedKeys=true,keyProperty="id") int insert(ClassExercise ce); @Select("SELECT * FROM class_exercise WHERE class_id=#{cid} AND exercise_id=#{eid}") ClassExercise findByClassIdAndExerciseId(@Param("cid") int cid, @Param("eid") int eid); @Update("UPDATE class_exercise SET publish_status=#{status}, published_at=#{at} WHERE id=#{id}") int updatePublishStatus(@Param("id") int id, @Param("status") String status, @Param("at") Date at); @Update("UPDATE class_exercise SET visible=#{v} WHERE id=#{id}") int updateVisibility(@Param("id") int id, @Param("v") boolean v); }